struct ListNode* addTwoNumbers(struct ListNode* l1, struct ListNode* l2) {
    struct ListNode dummy = {0, NULL}, *cur = &dummy;
    int carry = 0;
    while (l1 || l2 || carry) {
        if (l1) { carry += l1->val; l1 = l1->next; }
        if (l2) { carry += l2->val; l2 = l2->next; }
        cur->next = malloc(sizeof(struct ListNode));
        cur->next->val = carry % 10;
        cur->next->next = NULL;
        carry /= 10;
        cur = cur->next;
    }
    return dummy.next;
}

class Solution {
    public ListNode addTwoNumbers(ListNode l1, ListNode l2) {
        ListNode dummy = new ListNode(0), cur = dummy;
        int carry = 0;
        while (l1 != null || l2 != null || carry > 0) {
            if (l1 != null) { carry += l1.val; l1 = l1.next; }
            if (l2 != null) { carry += l2.val; l2 = l2.next; }
            cur.next = new ListNode(carry % 10);
            carry /= 10;
            cur = cur.next;
        }
        return dummy.next;
    }
}

class ListNode {
  constructor(val = 0, next = null) {
    this.val = val;
    this.next = next;
  }
}

export default function addTwoNumbers(l1, l2) {
  const dummy = new ListNode();
  let carry = 0;
  let cur = dummy;

  while (l1 || l2 || carry) {
    const sum = (l1?.val || 0) + (l2?.val || 0) + carry;

    carry = Math.floor(sum / 10);
    cur.next = new ListNode(sum % 10);
    cur = cur.next;

    l1 = l1?.next || null;
    l2 = l2?.next || null;
  }

  return dummy.next;
}

const transformMap = {
  plusOne: (value) => value + 1,
  plusIndex: (value, index) => value + index,
  constant42: () => 42
};

export default function map(arr, fn) {
  const transform = typeof fn === "function" ? fn : transformMap[fn];

  if (typeof transform !== "function") {
    throw new Error("Invalid transform");
  }

  const transformed = [];

  for (let index = 0; index < arr.length; index += 1) {
    transformed.push(transform(arr[index], index));
  }

  return transformed;
}

const reducerMap = {
  sum: (accum, curr) => accum + curr,
  sumSquares: (accum, curr) => accum + curr * curr,
  product: (accum, curr) => accum * curr
};

export default function reduce(nums, fn, init) {
  const reducer = typeof fn === "function" ? fn : reducerMap[fn];

  if (typeof reducer !== "function") {
    throw new Error("Invalid reducer");
  }

  let result = init;

  for (const num of nums) {
    result = reducer(result, num);
  }

  return result;
}

export default function createCounter(n, calls) {
  let current = n;

  const counter = () => current++;

  if (!Array.isArray(calls)) {
    return counter;
  }

  return calls.map(() => counter());
}

export default function createCounter(init, operations) {
  let current = init;

  const api = {
    increment() {
      current += 1;
      return current;
    },
    decrement() {
      current -= 1;
      return current;
    },
    reset() {
      current = init;
      return current;
    }
  };

  if (!Array.isArray(operations)) {
    return api;
  }

  return operations.map((operation) => api[operation]());
}

export default function createHelloWorld(calls) {
  const fn = (..._args) => "Hello World";

  if (!Array.isArray(calls)) {
    return fn;
  }

  return calls.map((args) => fn(...args));
}

const predicateMap = {
  greaterThan10: (value) => value > 10,
  firstIndex: (_, index) => index === 0,
  plusIndexTruthy: (value, index) => value + index
};

export default function filter(arr, fn) {
  const predicate = typeof fn === "function" ? fn : predicateMap[fn];

  if (typeof predicate !== "function") {
    throw new Error("Invalid predicate");
  }

  const filtered = [];

  for (let index = 0; index < arr.length; index += 1) {
    if (predicate(arr[index], index)) {
      filtered.push(arr[index]);
    }
  }

  return filtered;
}

