export default async function sleep(millis, mode) {
  const promise = new Promise((resolve) => {
    setTimeout(resolve, millis);
  });

  if (mode !== "measure") {
    return promise;
  }

  const start = Date.now();
  await promise;
  return Date.now() - start >= millis;
}

export default function expect(val, assertions) {
  const api = {
    toBe(other) {
      if (val === other) {
        return true;
      }

      throw new Error("Not Equal");
    },
    notToBe(other) {
      if (val !== other) {
        return true;
      }

      throw new Error("Equal");
    }
  };

  if (!Array.isArray(assertions)) {
    return api;
  }

  return assertions.map(({ method, arg }) => {
    try {
      return api[method](arg);
    } catch (error) {
      return error.message;
    }
  });
}

export default function solve(nums, target) {
  const seen = new Map();

  for (let index = 0; index < nums.length; index += 1) {
    const value = nums[index];
    const complement = target - value;

    if (seen.has(complement)) {
      return [seen.get(complement), index];
    }

    seen.set(value, index);
  }

  return [];
}
